"use client";
import { useEffect, useState } from "react";
import { Users, CheckCircle, Clock } from "lucide-react";
import { motion } from "framer-motion";
import { formatDate } from "@/lib/utils";

interface Assignment { id: string; status: string; assignedAt: string; need: { title: string; zone: string; severity: string }; volunteer: { user: { name: string } } }

const statusColors: Record<string, string> = { PENDING: "badge-medium", ACTIVE: "badge-low", COMPLETED: "badge-low", CANCELLED: "badge-critical" };

export default function AssignmentsPage() {
  const [data, setData] = useState<Assignment[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch("/api/assignments").then(r => r.json()).then(d => { setData(Array.isArray(d) ? d : []); setLoading(false); });
  }, []);

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      <div>
        <h1 className="text-3xl font-bold" style={{ fontFamily: "Plus Jakarta Sans", color: "var(--ink)" }}>Assignments</h1>
        <p className="text-sm mt-1" style={{ color: "var(--muted)" }}>Volunteer-to-need assignments across all zones</p>
      </div>
      <div className="glass rounded-2xl overflow-hidden">
        <div className="px-6 py-4 border-b" style={{ borderColor: "var(--green-pale)" }}>
          <h2 className="font-bold" style={{ color: "var(--ink)" }}>All Assignments</h2>
        </div>
        {loading ? (
          <div className="p-8 text-center text-sm" style={{ color: "var(--muted)" }}>Loading…</div>
        ) : data.length === 0 ? (
          <div className="p-12 text-center">
            <Users size={36} className="mx-auto mb-3" style={{ color: "var(--muted)" }} />
            <p className="font-bold" style={{ color: "var(--ink)" }}>No assignments yet</p>
            <p className="text-sm" style={{ color: "var(--muted)" }}>Assignments are created when volunteers are matched to community needs.</p>
          </div>
        ) : (
          <div className="divide-y" style={{ divideColor: "var(--green-pale)" }}>
            {data.map((a, i) => (
              <motion.div key={a.id} initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: i * 0.04 }}
                className="flex items-center gap-4 px-6 py-4">
                <div className="flex-1 min-w-0">
                  <p className="font-semibold text-sm" style={{ color: "var(--ink)" }}>{a.need.title}</p>
                  <p className="text-xs mt-0.5" style={{ color: "var(--muted)" }}>
                    {a.need.zone} · Volunteer: {a.volunteer.user.name} · {formatDate(a.assignedAt)}
                  </p>
                </div>
                <span className={`px-2 py-0.5 rounded-full text-xs font-bold ${statusColors[a.status] ?? "badge-low"}`}>{a.status}</span>
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
